const healthExec = $('Summary: Run research-health').item.json || {};
const statsExec = $('Summary: Run research-stats').item.json || {};
const healthStdout = (healthExec.stdout || '').toString().trim();
const statsStdout = (statsExec.stdout || '').toString().trim();
const healthData = safeParse(healthStdout);
const statsData = safeParse(statsStdout);
const healthChecks = Array.isArray(healthData && healthData.checks) ? healthData.checks : [];
const actionableChecks = healthChecks.filter((check) => {
  const status = (check.status || '').toUpperCase();
  const deferred = Boolean(check.data && check.data.deferred);
  return status === 'RED' || (status === 'YELLOW' && !deferred);
});
const topFamilies = Object.entries((statsData && statsData.docs_by_family) || {})
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([family, count]) => `${family}=${count}`)
  .join(', ');

const GREEN = 3066993;
const YELLOW = 16744448;
const RED = 16711680;

let embed;
const statsExitCode = Number(statsExec.exitCode || 0);
const healthSummary = (healthData && healthData.summary) || 'unknown';
const runCount = (healthData && healthData.run_count) || 0;

if (statsExitCode !== 0 || (statsData && statsData.__parseError)) {
  const errorDetail = statsData && statsData.__parseError
    ? `parse error: ${statsData.__parseError}`
    : `exit=${statsExitCode} | stderr: ${(statsExec.stderr || '').toString().replace(/\s+/g, ' ').trim().substring(0, 200)}`;
  embed = {
    title: 'RIS Daily Summary Error',
    description: `Health: ${healthSummary}`,
    color: RED,
    fields: [
      { name: 'Error Detail', value: errorDetail.substring(0, 300), inline: false },
    ],
    footer: { text: 'RIS | daily-summary' },
    timestamp: new Date().toISOString(),
  };
} else {
  const totalDocs = statsData.total_docs || 0;
  const totalClaims = statsData.total_claims || 0;
  const acquNew = statsData.acquisition_new || 0;
  const acquCached = statsData.acquisition_cached || 0;
  const acquErrors = statsData.acquisition_errors || 0;
  const prechecks = statsData.precheck_decisions || {};
  const color = actionableChecks.length > 0 ? YELLOW : GREEN;
  const fields = [
    { name: 'Docs', value: String(totalDocs), inline: true },
    { name: 'Runs', value: String(runCount), inline: true },
    { name: 'New', value: String(acquNew), inline: true },
    { name: 'Ingest Errors', value: String(acquErrors), inline: true },
  ];
  if (topFamilies) {
    fields.push({ name: 'Top Families', value: topFamilies, inline: false });
  }
  fields.push({ name: 'Prechecks', value: `GO=${prechecks.GO || 0}, CAUTION=${prechecks.CAUTION || 0}, STOP=${prechecks.STOP || 0}`, inline: false });
  if (actionableChecks.length > 0) {
    const top2 = actionableChecks.slice(0, 2).map((c) => `${c.check_name}=${c.status}`).join(', ');
    fields.push({ name: 'Actionable', value: top2.substring(0, 200), inline: false });
  }
  embed = {
    title: 'RIS Daily Summary',
    description: `Health: ${healthSummary}`,
    color,
    fields,
    footer: { text: 'RIS | daily-summary' },
    timestamp: new Date().toISOString(),
  };
}

