const webhook = $('Ingest: Webhook').item.json || {};
const exec = $json || {};
const body = webhook.body || {};
const errorText = (exec.stderr || exec.stdout || 'Unknown error').toString().replace(/\s+/g, ' ').trim();
const statusPayload = {
  status: 'failed',
  url: body.url,
  source_family: body.source_family,
  error: errorText.substring(0, 500),
  exitCode: exec.exitCode,
  timestamp: new Date().toISOString(),
};
const rawUrl = (statusPayload.url || '').toString();
let urlDisplay;
if (rawUrl.length <= 60) {
  urlDisplay = rawUrl || '(no url)';
} else {
  try {
    const u = new URL(rawUrl);
    const tail = rawUrl.slice(-20);
    urlDisplay = `${u.hostname}/...${tail}`;
  } catch (_) {
    urlDisplay = rawUrl.substring(0, 40) + '...' + rawUrl.slice(-20);
  }
}
const errorDisplay = statusPayload.error.substring(0, 300);
const family = (statusPayload.source_family || 'unknown');
const familyDisplay = family.charAt(0).toUpperCase() + family.slice(1);
let description;
if (statusPayload.exitCode != null) {
  description = `Exit ${statusPayload.exitCode} | Family: ${familyDisplay}`;
} else {
  description = `Family: ${familyDisplay}`;
}
const fields = [];
if (rawUrl) {
  fields.push({ name: 'Source', value: urlDisplay, inline: true });
}
fields.push({ name: 'Detail', value: errorDisplay || 'Unknown error', inline: false });
const embed = {
  title: `Ingest Failed: ${familyDisplay}`,
  description,
  color: 16711680,
  fields,
  footer: { text: 'RIS | ingest' },
  timestamp: new Date().toISOString(),
};
const rawWebhookUrl = '__RIS_OPERATOR_WEBHOOK_URL__';
const webhookUrl = (String(rawWebhookUrl).startsWith('http://') || String(rawWebhookUrl).startsWith('https://')) ? String(rawWebhookUrl).trim() : '';
const notifyEnabled = webhookUrl.length > 0;
return [{ json: { ...statusPayload, embeds: [embed], webhookUrl, notifyEnabled } }];
